const DICTS: Record<Lang, Dict> = { fr, en, nl, es, pt, it, el, ru, sw }
const KEY = 'planii.lang'

function detect(): Lang {
  try {
    const saved = localStorage.getItem(KEY) as Lang | null
    if (saved && DICTS[saved]) return saved
  } catch { /* ignore */ }
  const nav = (navigator.language || 'fr').slice(0, 2).toLowerCase()
  return (['fr', 'en', 'nl', 'es', 'pt', 'it', 'el', 'ru', 'sw'].includes(nav) ? nav : 'fr') as Lang
}

let current: Lang = detect()
const listeners = new Set<() => void>()

export function getLang(): Lang { return current }
export function setLang(l: Lang) {
  current = l
  try { localStorage.setItem(KEY, l) } catch { /* ignore */ }
  document.documentElement.lang = l
  listeners.forEach((fn) => fn())
  // Mémorise côté serveur (mails transactionnels dans la langue du destinataire)
  try { if (getTok()) api('PATCH', '/me', { lang: l }).catch(() => {}) } catch { /* hors session */ }
}

/** Traduit une clé dans la langue active (repli : français, puis la clé elle-même).
 *  Variables : t('x', { n: 3 }) remplace {n} dans la chaîne. */
export function t(key: string, vars?: Record<string, string | number>): string {
  let s = DICTS[current][key] ?? en[key] ?? fr[key] ?? key
  if (vars) for (const [k, v] of Object.entries(vars)) s = s.split('{' + k + '}').join(String(v))
  return s
}


/** Traduction d'affichage des termes par défaut (Travail, Privé, Tâche, Bug, rôles types).
 *  Les valeurs personnalisées de l'utilisateur sont renvoyées telles quelles. */
const TERM_KEYS: Record<string, string> = {
  'travail': 'term.work', 'work': 'term.work', 'werk': 'term.work', 'trabajo': 'term.work', 'trabalho': 'term.work',
  'privé': 'term.private', 'prive': 'term.private', 'private': 'term.private', 'privado': 'term.private',
  'tâche': 'term.task', 'tache': 'term.task', 'task': 'term.task', 'taak': 'term.task', 'tarea': 'term.task', 'tarefa': 'term.task',
  'bug': 'term.bug',
  'amélioration': 'term.improvement', 'amelioration': 'term.improvement', 'improvement': 'term.improvement',
  'chef de projet': 'term.pm', 'project manager': 'term.pm', 'projectleider': 'term.pm',
  'développeur': 'term.dev', 'developpeur': 'term.dev', 'developer': 'term.dev', 'ontwikkelaar': 'term.dev', 'desarrollador': 'term.dev', 'programador': 'term.dev',
  'consultant': 'term.consultant', 'consultor': 'term.consultant',
  'à faire': 'term.todo', 'a faire': 'term.todo', 'en cours': 'term.doing', 'revu': 'term.reviewSt', 'terminé': 'term.doneSt', 'termine': 'term.doneSt', 'transféré': 'term.transferredSt', 'transfere': 'term.transferredSt',
}
export function trTerm(v: string): string {
  const k = TERM_KEYS[(v || '').trim().toLowerCase()]
  return k ? t(k) : v
}

/** Hook : abonne le composant aux changements de langue. Retourne { t, lang, setLang }. */
export function useI18n() {
  const [, force] = useState(0)
  useEffect(() => {
    const fn = () => force((n) => n + 1)
    listeners.add(fn)
    return () => { listeners.delete(fn) }
  }, [])
  return { t, lang: current, setLang }
}

/** Sélecteur de langue (utilisé dans le Profil et l'écran de connexion). */
export function LangFlags() {
  const { lang, setLang } = useI18n()
  return (
    <div className="lang-flags" role="group" aria-label={t('lang.title')}>
      {LANGS.map((l) => (
        <button key={l.code} className={'lang-flag' + (lang === l.code ? ' on' : '')} onClick={() => setLang(l.code)} title={l.label} aria-label={l.label}>
          <span aria-hidden>{l.flag}</span>
        </button>
      ))}
    </div>
  )
}

export function LangPicker({ compact }: { compact?: boolean }) {
  const { lang, setLang } = useI18n()
  if (compact) {
    return (
      <select className="lang-select" value={lang} onChange={(e) => setLang(e.target.value as Lang)} aria-label={t('lang.title')}>
        {LANGS.map((l) => <option key={l.code} value={l.code}>{l.flag} {l.label}</option>)}
      </select>
    )
  }
  return (
    <div className="seg lang-seg">
      {LANGS.map((l) => (
        <button key={l.code} className={lang === l.code ? 'on' : ''} onClick={() => setLang(l.code)}>
          <span aria-hidden>{l.flag}</span> {l.label}
        </button>
      ))}
    </div>
  )
}

document.documentElement.lang = current
